import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"ARTI Cross-Repository Contracts","description":"","frontmatter":{"status":"Draft","owner":"待指定","scope":"project","project":"arti","last_reviewed":"2026-06-15T00:00:00.000Z"},"headers":[],"relativePath":"ai-native/case-studies/arti-contracts-explicit.md","filePath":"ai-native/case-studies/arti-contracts-explicit.md"}'),o={name:"ai-native/case-studies/arti-contracts-explicit.md"};function l(d,t,c,s,n,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="arti-cross-repository-contracts" tabindex="-1">ARTI Cross-Repository Contracts <a class="header-anchor" href="#arti-cross-repository-contracts" aria-label="Permalink to &quot;ARTI Cross-Repository Contracts&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>Owner：待指定</strong></p><h2 id="背景与目标" tabindex="-1">背景与目标 <a class="header-anchor" href="#背景与目标" aria-label="Permalink to &quot;背景与目标&quot;">​</a></h2><p>ARTI 由 Main app、Backend、Poly、CLI 和共享 Supabase 组成。多个仓库共同依赖报告任务、通知、Credits、共享标识符等契约。</p><p>目标：把跨仓不变量写清楚，减少“看哪个仓库都像真源”的情况。</p><h2 id="原有方式" tabindex="-1">原有方式 <a class="header-anchor" href="#原有方式" aria-label="Permalink to &quot;原有方式&quot;">​</a></h2><ul><li>事实散在 RFC、migration、代码和历史实现里。</li><li>Agent 或新人容易按单仓局部理解改动。</li><li>共享 DB、通知类型、Report Type、Symbol 规则有漂移风险。</li></ul><h2 id="引入的实践" tabindex="-1">引入的实践 <a class="header-anchor" href="#引入的实践" aria-label="Permalink to &quot;引入的实践&quot;">​</a></h2><ul><li>建立 <code>projects/arti/contracts/</code>。</li><li>每份 Contract 只写 Owner、不变量、生产者、消费者和变更方式。</li><li>字段级细节继续链接到代码、migration 或 RFC。</li><li>对已知漂移新增 Known Drift Review。</li></ul><h2 id="责任分配" tabindex="-1">责任分配 <a class="header-anchor" href="#责任分配" aria-label="Permalink to &quot;责任分配&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>责任</th></tr></thead><tbody><tr><td>项目 Owner</td><td>判断跨仓边界和优先级</td></tr><tr><td>仓库 Owner</td><td>维护本仓真源和验证</td></tr><tr><td>Agent</td><td>搜索引用、整理契约、指出漂移</td></tr><tr><td>Reviewer</td><td>检查是否复制了第二份真源</td></tr></tbody></table><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to &quot;结果&quot;">​</a></h2><p>已形成第一批 ARTI 契约：</p><ul><li><code>report-tasks.md</code></li><li><code>report-result.md</code></li><li><code>credits-and-settlement.md</code></li><li><code>notifications.md</code></li><li><code>shared-identifiers.md</code></li></ul><p>同时补了：</p><ul><li><code>shared-database-change.md</code></li><li><code>known-drift-review.md</code></li><li><code>ARTI-D007</code></li></ul><h2 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h2><ul><li>仍有 <code>Current with Known Drift</code>。</li><li>契约不是 schema 真源，不能替代代码检查。</li><li>Owner 还需要进一步明确到团队或角色。</li><li>还缺跨仓自动漂移测试。</li></ul><h2 id="可复用结论" tabindex="-1">可复用结论 <a class="header-anchor" href="#可复用结论" aria-label="Permalink to &quot;可复用结论&quot;">​</a></h2><ul><li>跨仓 Contract 应写“不变量和变更规则”，不要复制完整实现。</li><li>已知漂移不要伪装成完成，应单独标出并给复核流程。</li><li>对 Agent 友好的契约能减少误读，但不能替代 Owner 审查。</li></ul><h2 id="证据" tabindex="-1">证据 <a class="header-anchor" href="#证据" aria-label="Permalink to &quot;证据&quot;">​</a></h2><ul><li><code>projects/arti/contracts/README.md</code></li><li><code>projects/arti/contracts/shared-identifiers.md</code></li><li><code>projects/arti/contracts/notifications.md</code></li><li><code>projects/arti/playbooks/known-drift-review.md</code></li><li><code>projects/arti/decisions/ARTI-D007-shared-identifier-drift-review.md</code></li></ul>',23)])])}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
